class OAuthClient {
    constructor(clientId, clientIdSecret, authorizationServerUrl, redirectUri) {
        this.clientId = clientId;
        this.clientSecret = clientIdSecret;
        this.authorizationServerUrl = authorizationServerUrl;
        this.redirectUri = redirectUri;

        this.accessToken = null;
        this.refreshToken = null;
        this.expirationDate = new Date();

        if (localStorage.getItem('accessToken')) {
            this.accessToken = localStorage.getItem('accessToken');
            this.expirationDate = new Date(localStorage.getItem('expirationDate'));
            this.refreshToken = localStorage.getItem('refreshToken');

            if (!this.isAccessTokenValid()) {
                // token has expired, try to refresh it
                this.refreshAccessToken();
            }
        }
    }

    isAccessTokenValid() {
        const currentTime = new Date();
        return currentTime < this.expirationDate;
    }

    getAccessToken() {
        return this.accessToken;
    }

    refreshTokenCallback(accessTokenn, refreshToken, expirationDate) {
        this.accessToken = accessTokenn;
        localStorage.setItem('accessToken', accessTokenn);
        this.refreshToken = refreshToken;
        localStorage.setItem('refreshToken', refreshToken);
        this.expirationDate = expirationDate;
        localStorage.setItem('expirationDate', expirationDate.getTime());
    }

    refreshAccessToken() {
        const refreshTokenEndpointUrl = `${this.authorizationServerUrl}/token`;
        const data = `grant_type=refresh_token&client_id=${this.clientId}&client_secret=${this.clientSecret}&refresh_token=${this.refreshToken}`;

        fetch(refreshTokenEndpointUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: data
        })
        .then(response => response.json())
        .then(data => {
            this.refreshTokenCallback(data.access_token, data.refresh_token, new Date(Date.now() + 300000)); // token expires in 5 minutes
            console.log('Access Token refreshed');
        })
        .catch(error => console.error('Error refreshing access token:', error));
    }

    login() {
        const authorizationUrl = `${this.authorizationServerUrl}/authorize`;
        const params = `response_type=code&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=openid profile email`;

        window.location.href = `${authorizationUrl}?${params}`;
    }
}